/** Interop KAT vs libcrux `kyber1024` (NIST Round-3 — what libsignal's PQXDH uses for
 * KEM type 0x08): the crate's encapsulate shared secret must equal our decapsulation,
 * which is ML-KEM-1024 decaps + the Round-3 final KDF (kyber.ts). Fixture generated by
 * a Rust harness against the upstream libcrux crate. Guards the Round-3 KDF. */
import { ml_kem1024 } from "@noble/post-quantum/ml-kem.js";
import { sha3_256, shake256 } from "@noble/hashes/sha3.js";
import { hexToBytes, bytesToHex, concatBytes } from "@noble/hashes/utils.js";
import { expect, test } from "vitest";

const SK = "";
const CT = "";
const SS = "3c97f0555623b49f742cd0b6ed95b867c2ae985dda9776f9fb415f7e24f89804";

test("libcrux kyber1024 ct → our Round-3 decapsulation recovers the shared secret", () => {
  let sk = hexToBytes(SK), ct = hexToBytes(CT);
  let mlkemSecret = ml_kem1024.decapsulate(ct, sk); // FIPS-203 secret (pre-KDF)
  let ss = bytesToHex(shake256(concatBytes(mlkemSecret, sha3_256(ct)), { dkLen: 32 }));
  expect(ss).toBe(SS);
});
